    31→
    32→/// A page widget class to manage user lists.
    33→class AdminPage extends HookConsumerWidget {
    34→  const AdminPage({super.key});
    35→
    36→  @override
    37→  Widget build(BuildContext context, WidgetRef ref) {
    38→    // Custom hook for handling access denied scenarios
    39→    final handleAccessDenied = useAccessDeniedNavigation();
    40→
    41→    // Get team and access info
    42→    final teamId =
    43→        ref.watch(profileStorageProvider.select((p) => p.getTeamId()));
    44→    final accessibleContents =
    45→        ref.watch(userAccessibleContentsControllerProvider);
    46→
    47→    // Early return if teamId is null
    48→    if (teamId == null) {
    49→      handleAccessDenied();
    50→      return const Scaffold(
    51→        body: Center(child: CircularProgressIndicator()),
    52→      );
    53→    }
    54→
    55→    // Check if user has management read access
    56→    final hasManagementAccess = accessibleContents?.hasPrivilegesFor(
    57→          teamId,
    58→          RoleDomain.management,
    59→          RoleLevel.read,
    60→          true,
    61→        ) ??
    62→        false;
    63→
    64→    // If user doesn't have management access, redirect to settings page
    65→    if (!hasManagementAccess) {
    66→      handleAccessDenied();
    67→      return const Scaffold(
    68→        body: Center(child: CircularProgressIndicator()),
    69→      );
    70→    }
    71→
    72→    final shouldShowEditButton = accessibleContents?.hasPrivilegesFor(
    73→          teamId,
    74→          RoleDomain.management,
    75→          RoleLevel.write,
    76→          true,
    77→        ) ??
    78→        false;
    79→
    80→    // Main widget tree
    81→    return Scaffold(
    82→      appBar: _AdminPageAppBar(),
    83→      body: SafeArea(
    84→        child: Padding(
    85→          padding: HomePage.bodyPadding,
    86→          child: RefreshIndicator(
    87→            onRefresh: () async {
    88→              if (!context.mounted) return;
    89→
    90→              // Refresh accessible contents first to get latest permissions
    91→              final updatedAccessibleContents = await ref
    92→                  .read(userAccessibleContentsControllerProvider.notifier)
    93→                  .refresh();
    94→
    95→              if (!context.mounted) return;
    96→
    97→              final stillHasAccess =
    98→                  updatedAccessibleContents?.hasPrivilegesFor(
    99→                        teamId,
   100→                        RoleDomain.management,
   101→                        RoleLevel.read,
   102→                        true,
   103→                      ) ??
   104→                      false;
   105→
   106→              if (!stillHasAccess) {
   107→                // User lost access, navigate to settings page
   108→                handleAccessDenied();
   109→                return;
   110→              }
   111→
   112→              // Only refresh member list if user still has access
   113→              if (context.mounted) {
   114→                ref.invalidate(userInfoControllerProvider);
   115→                ref.invalidate(memberListControllerProvider);
   116→              }
   117→            },
   118→            child: const MemberList(),
   119→          ),
   120→        ),
   121→      ),
   122→      floatingActionButton: shouldShowEditButton
   123→          ? FloatingActionButton(
   124→              onPressed: () {
   125→                Navigator.of(context).pushNamed(HomeRouter.inviteMemberPage);
   126→              },
   127→              child: Icon(Icons.person_add_alt),
   128→            )
   129→          : null,
   130→    );
   131→  }
   132→}
   133→
   134→class _AdminPageAppBar extends HookConsumerWidget
   135→    implements PreferredSizeWidget {
   136→  const _AdminPageAppBar();
   137→
   138→  @override
   139→  Size get preferredSize => const Size.fromHeight(kToolbarHeight);
   140→
   141→  @override
   142→  Widget build(BuildContext context, WidgetRef ref) {
   143→    final teamId =
   144→        ref.watch(profileStorageProvider.select((p) => p.getTeamId()));
   145→    final accessibleContents =
   146→        ref.watch(userAccessibleContentsControllerProvider);
   147→
   148→    // Return basic app bar if teamId is null
   149→    if (teamId == null) {
   150→      return const CustomAppBar(
   151→        titleWidget: Text('Admin'),
   152→      );
   153→    }
   154→
   155→    final shouldShowEditButton = accessibleContents?.hasPrivilegesFor(
   156→          teamId,
   157→          RoleDomain.management,
   158→          RoleLevel.write,
   159→          true,
   160→        ) ??
   161→        false;
   162→    return CustomAppBar(
   163→      // Title: Team icon and name
   164→      titleWidget: ref.watch(userInfoControllerProvider).fold(
   165→            loading: () => const SizedBox.shrink(),
   166→            error: (_) => const SizedBox.shrink(),
   167→            data: (userInfo) {
