/// {@category Containers}
library;

// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/member_list_controller.dart';
import 'package:baseball_detector_flutter/controllers/team_list_controller.dart';
import 'package:baseball_detector_flutter/controllers/user_accessible_contents_controller.dart';
import 'package:baseball_detector_flutter/controllers/user_info_controller.dart';
import 'package:baseball_detector_flutter/data/models/enums/role_domain.dart';
import 'package:baseball_detector_flutter/data/models/enums/role_level.dart';
import 'package:baseball_detector_flutter/data/models/user_info.dart';
import 'package:baseball_detector_flutter/data/result.dart';
import 'package:baseball_detector_flutter/gen/assets.gen.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/utils/build_context_ext.dart';
import 'package:baseball_detector_flutter/views/components/custom_app_bar.dart';
import 'package:baseball_detector_flutter/views/components/s3_image.dart';
import 'package:baseball_detector_flutter/views/hooks/use_access_denied_navigation.dart';
import 'package:baseball_detector_flutter/views/pages/home/admin/components/member_list.dart';
import 'package:baseball_detector_flutter/views/pages/home/home_page.dart';
import 'package:baseball_detector_flutter/views/routers/home_router.dart';
import 'package:baseball_detector_flutter/views/themes/color_manager.dart';
import 'package:baseball_detector_flutter/views/themes/font_manager.dart';

/// A page widget class to manage user lists.
class AdminPage extends HookConsumerWidget {
  const AdminPage({super.key});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    // Custom hook for handling access denied scenarios
    final handleAccessDenied = useAccessDeniedNavigation();

    // Get team and access info
    final teamId =
        ref.watch(profileStorageProvider.select((p) => p.getTeamId()));
    final accessibleContents =
        ref.watch(userAccessibleContentsControllerProvider);

    // Early return if teamId is null
    if (teamId == null) {
      handleAccessDenied();
      return const Scaffold(
        body: Center(child: CircularProgressIndicator()),
      );
    }

    // Check if user has management read access
    final hasManagementAccess = accessibleContents?.hasPrivilegesFor(
          teamId,
          RoleDomain.management,
          RoleLevel.read,
          true,
        ) ??
        false;

    // If user doesn't have management access, redirect to settings page
    if (!hasManagementAccess) {
      handleAccessDenied();
      return const Scaffold(
        body: Center(child: CircularProgressIndicator()),
      );
    }

    final shouldShowEditButton = accessibleContents?.hasPrivilegesFor(
          teamId,
          RoleDomain.management,
          RoleLevel.write,
          true,
        ) ??
        false;

    // Main widget tree
    return Scaffold(
      appBar: _AdminPageAppBar(),
      body: SafeArea(
        child: Padding(
          padding: HomePage.bodyPadding,
          child: RefreshIndicator(
            onRefresh: () async {
              if (!context.mounted) return;

              // Refresh accessible contents first to get latest permissions
              final updatedAccessibleContents = await ref
                  .read(userAccessibleContentsControllerProvider.notifier)
                  .refresh();

              if (!context.mounted) return;

              final stillHasAccess =
                  updatedAccessibleContents?.hasPrivilegesFor(
                        teamId,
                        RoleDomain.management,
                        RoleLevel.read,
                        true,
                      ) ??
                      false;

              if (!stillHasAccess) {
                // User lost access, navigate to settings page
                handleAccessDenied();
                return;
              }

              // Only refresh member list if user still has access
              if (context.mounted) {
                ref.invalidate(userInfoControllerProvider);
                ref.invalidate(memberListControllerProvider);
              }
            },
            child: const MemberList(),
          ),
        ),
      ),
      floatingActionButton: shouldShowEditButton
          ? FloatingActionButton(
              onPressed: () {
                Navigator.of(context).pushNamed(HomeRouter.inviteMemberPage);
              },
              child: Icon(Icons.person_add_alt),
            )
          : null,
    );
  }
}

class _AdminPageAppBar extends HookConsumerWidget
    implements PreferredSizeWidget {
  const _AdminPageAppBar();

  @override
  Size get preferredSize => const Size.fromHeight(kToolbarHeight);

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final teamId =
        ref.watch(profileStorageProvider.select((p) => p.getTeamId()));
    final accessibleContents =
        ref.watch(userAccessibleContentsControllerProvider);

    // Return basic app bar if teamId is null
    if (teamId == null) {
      return const CustomAppBar(
        titleWidget: Text('Admin'),
      );
    }

    final shouldShowEditButton = accessibleContents?.hasPrivilegesFor(
          teamId,
          RoleDomain.management,
          RoleLevel.write,
          true,
        ) ??
        false;
    return CustomAppBar(
      // Title: Team icon and name
      titleWidget: ref.watch(userInfoControllerProvider).fold(
            loading: () => const SizedBox.shrink(),
            error: (_) => const SizedBox.shrink(),
            data: (userInfo) {
              final teamId = ref
                  .watch(profileStorageProvider.select((p) => p.getTeamId()));
              var team = userInfo.getTeam(teamId!);

              // For super_admin users, get team from team list if not found in user info
              if (team == null) {
                final teamListResult = ref.watch(teamListControllerProvider);
                team = teamListResult.fold(
                  loading: () => null,
                  error: (_) => null,
                  data: (result) =>
                      result.where((t) => t.id == teamId).firstOrNull,
                );
              }

              return Row(
                mainAxisAlignment: MainAxisAlignment.center,
                crossAxisAlignment: CrossAxisAlignment.center,
                children: [
                  if (shouldShowEditButton) const SizedBox(width: 40),
                  Container(
                    width: 32,
                    height: 32,
                    decoration: BoxDecoration(
                      borderRadius: BorderRadius.circular(4),
                      border: Border.all(
                        color: ColorManager.avatarBorder,
                        width: 1,
                      ),
                    ),
                    child: ClipRRect(
                      borderRadius: BorderRadius.circular(3),
                      child: S3Image(
                        url: team?.presignedImageUrl,
                        placeholder: Assets.images.imgTeam.image(),
                        imageErrorBuilder: (_, __, ___) =>
                            Assets.images.imgTeam.image(),
                      ),
                    ),
                  ),
                  const SizedBox(width: 12),
                  Builder(
                    builder: (context) {
                      final maxWidth = context.screenWidth *
                          (context.isPortrait ? 0.55 : 0.5);
                      return ConstrainedBox(
                        constraints: BoxConstraints(maxWidth: maxWidth),
                        child: Text(
                          (team?.name ?? '').isNotEmpty
                              ? team!.name!
                              : context.l10n.no_team_name,
                          style: TextStyleManager.appBar,
                          overflow: TextOverflow.ellipsis,
                          maxLines: 1,
                          textAlign: TextAlign.center,
                        ),
                      );
                    },
                  ),
                ],
              );
            },
          ),
      // Action: Edit button if user has write access
      actionWidgets: [
        if (shouldShowEditButton)
          IconButton(
            icon: const Icon(Icons.settings),
            tooltip: context.l10n.admin_page__edit,
            onPressed: () {
              Navigator.of(context).pushNamed(HomeRouter.editTeamPage);
            },
          ),
      ],
    );
  }
}

