     7→
     8→// Project imports:
     9→import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
    10→import 'package:baseball_detector_flutter/utils/build_context_ext.dart';
    11→import 'package:baseball_detector_flutter/views/hooks/use_effect_once.dart';
    12→
    13→class SearchableDropdownMenu<T> extends HookWidget {
    14→  const SearchableDropdownMenu({
    15→    required this.itemList,
    16→    required this.hintText,
    17→    required this.itemBuilder,
    18→    required this.displayString,
    19→    required this.onChanged,
    20→    this.includeHintTextToList = false,
    21→    this.value,
    22→    this.decoration,
    23→    super.key,
    24→  });
    25→
    26→  final List<T> itemList;
    27→  final String hintText;
    28→  final Widget Function(T) itemBuilder;
    29→  final String Function(T) displayString;
    30→  final ValueChanged<T?> onChanged;
    31→  final bool includeHintTextToList;
    32→  final T? value;
    33→  final InputDecoration? decoration;
    34→
    35→  @override
    36→  Widget build(BuildContext context) {
    37→    final layerLink = useMemoized(() => LayerLink());
    38→    final overlayEntryRef = useRef<OverlayEntry?>(null);
    39→    final controller = useTextEditingController();
    40→    final focusNode = useFocusNode();
    41→    final selectedRef = useRef<T?>(value);
    42→
    43→    void hideOverlay() {
    44→      overlayEntryRef.value?.remove();
    45→      overlayEntryRef.value = null;
    46→    }
    47→
    48→    void showOverlay() {
    49→      if (overlayEntryRef.value != null) return;
    50→
    51→      overlayEntryRef.value = createOverlayEntry(
    52→        context: context,
    53→        layerLink: layerLink,
    54→        controller: controller,
    55→        onTap: () {
    56→          // フィールド外タップで閉じる
    57→          focusNode.unfocus();
    58→          hideOverlay();
    59→        },
    60→        onSelect: (item) {
    61→          onChanged(item);
    62→          controller.text = item != null ? displayString(item) : '';
    63→          // 選択後はフォーカスを外して閉じる
    64→          focusNode.unfocus();
    65→          hideOverlay();
    66→        },
    67→      );
    68→
    69→      Overlay.of(context).insert(overlayEntryRef.value!);
    70→    }
    71→
    72→    // 入力変化でリスト更新のため Overlay を再描画
    73→    void requestOverlayRebuild() {
    74→      if (overlayEntryRef.value == null) return;
    75→      final phase = WidgetsBinding.instance.schedulerPhase;
    76→      if (phase == SchedulerPhase.idle ||
    77→          phase == SchedulerPhase.postFrameCallbacks) {
    78→        overlayEntryRef.value!.markNeedsBuild();
    79→      } else {
    80→        WidgetsBinding.instance.addPostFrameCallback((_) {
    81→          overlayEntryRef.value?.markNeedsBuild();
    82→        });
    83→      }
    84→    }
    85→
    86→    // 初期選択値と表示テキストの同期
    87→    useEffect(() {
    88→      selectedRef.value = value;
    89→      if (value != null) {
    90→        controller.text = displayString(value as T);
    91→      } else if (!focusNode.hasFocus && controller.text.isNotEmpty) {
    92→        // フォーカス外かつ選択解除された場合はテキストも消す
    93→        controller.text = '';
    94→      }
    95→      return null;
    96→    }, [value]);
    97→
    98→    // フォーカスで開閉
    99→    useEffectOnce(() {
   100→      // 文字列比較ユーティリティ: 前後空白を無視しつつ大文字小文字も区別しないで比較する
   101→      bool equalsIgnoreCaseTrim(String a, String b) =>
   102→          a.trim().toLowerCase() == b.trim().toLowerCase();
   103→
   104→      // 入力テキストと完全一致（空白・大小無視）する候補 T を探す
   105→      T? findExactItemByText(String text) {
   106→        final q = text.trim();
   107→        if (q.isEmpty) return null;
   108→        for (final e in itemList) {
   109→          if (equalsIgnoreCaseTrim(displayString(e), q)) return e;
   110→        }
   111→        return null;
   112→      }
   113→
   114→      // 選択値に応じてテキストフィールドを同期（選択が null なら入力をクリア）
   115→      void syncTextToSelection(T? selection) {
   116→        if (selection != null) {
   117→          controller.text = displayString(selection);
   118→        } else {
   119→          controller.clear();
   120→        }
   121→      }
   122→
   123→      // テキストフィールドが「現在選択の表示文字列」と同一なら、検索しやすいように一旦クリア
   124→      void clearIfShowingSelectedText() {
   125→        final current = selectedRef.value;
   126→        if (current == null) return;
   127→        final selectedText = displayString(current as T);
   128→        if (equalsIgnoreCaseTrim(controller.text, selectedText)) {
   129→          controller.clear();
   130→        }
   131→      }
   132→
   133→      // フォーカス喪失時の確定処理:
   134→      // 1) 入力と完全一致する候補があれば選択して onChanged を発火
   135→      // 2) 一致が無ければ既存の選択へ戻す（未選択ならクリア）
   136→      void applyExactMatchOrRestore() {
   137→        final exact = findExactItemByText(controller.text);
   138→
   139→        if (exact != null) {
   140→          if (selectedRef.value != exact) {
   141→            onChanged(exact);
   142→            selectedRef.value = exact;
   143→          }
   144→          syncTextToSelection(exact);
   145→          return;
   146→        }
   147→
   148→        // 一致なし: 既存選択へ戻す or クリア
   149→        syncTextToSelection(selectedRef.value);
   150→      }
   151→
   152→      void focusListener() {
   153→        if (focusNode.hasFocus) {
   154→          // 既定値の表示文字列が入っている場合は検索開始しやすいようにクリア
   155→          clearIfShowingSelectedText();
   156→          showOverlay();
   157→        } else {
   158→          // フォーカスが外れたら、完全一致があれば確定、なければ元に戻す
   159→          applyExactMatchOrRestore();
   160→          hideOverlay();
   161→        }
   162→      }
   163→
   164→      focusNode.addListener(focusListener);
   165→      controller.addListener(requestOverlayRebuild);
   166→      return () {
   167→        focusNode.removeListener(focusListener);
   168→        controller.removeListener(requestOverlayRebuild);
   169→        hideOverlay();
   170→      };
   171→    });
   172→
   173→    return CompositedTransformTarget(
   174→      link: layerLink,
   175→      child: TextField(
   176→        controller: controller,
   177→        focusNode: focusNode,
   178→        readOnly: false,
   179→        onTap: showOverlay,
   180→        style: Theme.of(context).textTheme.bodyLarge,
   181→        decoration: (() {
   182→          final defaultDecoration = InputDecoration(
   183→            border: OutlineInputBorder(
   184→              borderRadius: BorderRadius.circular(4),
   185→            ),
   186→            contentPadding:
   187→                const EdgeInsets.symmetric(vertical: 16, horizontal: 12),
   188→          );
   189→
   190→          final base =
   191→              (decoration ?? defaultDecoration).copyWith(hintText: hintText);
   192→
   193→          final resolvedSuffix = base.suffixIcon ??
   194→              ((controller.text.isNotEmpty || value != null)
   195→                  ? IconButton(
   196→                      icon: const Icon(Icons.clear, size: 18),
   197→                      onPressed: () {
   198→                        controller.clear();
   199→                        onChanged(null);
   200→                        if (focusNode.hasFocus) showOverlay();
   201→                      },
   202→                    )
   203→                  : const Icon(Icons.arrow_drop_down));
   204→
   205→          return base.copyWith(
   206→            suffixIcon: resolvedSuffix,
   207→          );
   208→        })(),
   209→      ),
   210→    );
   211→  }
   212→
   213→  // OverlayEntry を作るローカルメソッド
   214→  OverlayEntry createOverlayEntry({
   215→    required BuildContext context,
   216→    required LayerLink layerLink,
   217→    required TextEditingController controller,
   218→    required VoidCallback onTap,
   219→    required ValueChanged<T?> onSelect,
   220→  }) {
   221→    final renderBox = context.findRenderObject() as RenderBox;
   222→    final size = renderBox.size;
   223→    final offset = renderBox.localToGlobal(Offset.zero);
   224→
   225→    List<T> filtered() {
   226→      final q = controller.text.trim().toLowerCase();
   227→      if (q.isEmpty) return itemList;
   228→      return itemList.where((e) {
   229→        final s = displayString(e).toLowerCase();
   230→        return s.contains(q);
   231→      }).toList();
   232→    }
   233→
   234→    const double baseX = 0.0;
   235→    final double baseY = size.height;
   236→
   237→    return OverlayEntry(
   238→      builder: (context) => GestureDetector(
   239→        behavior: HitTestBehavior.translucent,
   240→        onTap: onTap,
   241→        child: Stack(
   242→          children: [
   243→            Positioned(
   244→              left: offset.dx,
   245→              top: offset.dy,
   246→              width: size.width,
   247→              child: CompositedTransformFollower(
   248→                link: layerLink,
   249→                showWhenUnlinked: false,
   250→                offset: _resolveFollowerOffsetX(
   251→                  baseX: baseX,
   252→                  baseY: baseY,
   253→                  fieldGlobalX: offset.dx,
   254→                  dropdownWidth: size.width,
   255→                  screenWidth: MediaQuery.of(context).size.width,
   256→                ),
   257→                child: Material(
   258→                  elevation: 8,
   259→                  shape: RoundedRectangleBorder(
   260→                    borderRadius: BorderRadius.circular(8.0),
   261→                    side: BorderSide(
   262→                      color:
   263→                          Theme.of(context).dividerColor.withValues(alpha: 0.6),
   264→                    ),
   265→                  ),
   266→                  clipBehavior: Clip.antiAlias,
   267→                  child: Builder(
   268→                    builder: (context) {
   269→                      final items = filtered();
   270→                      final maxHeightPx = context.screenHeight * 0.3;
   271→                      const tileHeight = 56.0; // 1行の標準行高
   272→
   273→                      final itemCount = (items.isEmpty ? 1 : items.length) +
   274→                          (includeHintTextToList ? 1 : 0);
   275→                      final desiredHeight = itemCount * tileHeight;
   276→                      final overlayHeight = desiredHeight <= maxHeightPx
   277→                          ? desiredHeight.toDouble()
   278→                          : maxHeightPx;
   279→
   280→                      if (items.isEmpty) {
   281→                        return SizedBox(
   282→                          height: overlayHeight,
   283→                          child: ListView(
   284→                            padding: EdgeInsets.zero,
   285→                            children: [
   286→                              if (includeHintTextToList)
   287→                                ListTile(
   288→                                  title: Text(hintText),
   289→                                  onTap: () => onSelect(null),
   290→                                  selected:
   291→                                      value == null && controller.text.isEmpty,
   292→                                ),
   293→                              ListTile(
   294→                                title: Text(context.l10n.common__no_data),
   295→                              ),
   296→                            ],
   297→                          ),
   298→                        );
   299→                      } else {
   300→                        return SizedBox(
   301→                          height: overlayHeight,
   302→                          child: ListTileTheme(
   303→                            child: ListView(
   304→                              padding: EdgeInsets.zero,
   305→                              children: [
   306→                                if (includeHintTextToList)
   307→                                  ListTile(
   308→                                    title: Text(hintText),
   309→                                    onTap: () => onSelect(null),
   310→                                    selected: value == null &&
   311→                                        controller.text.isEmpty,
   312→                                  ),
   313→                                ...items.map(
   314→                                  (item) => ListTile(
   315→                                    title: itemBuilder(item),
   316→                                    onTap: () => onSelect(item),
   317→                                    selected: value == item,
   318→                                  ),
   319→                                ),
   320→                              ],
   321→                            ),
   322→                          ),
   323→                        );
   324→                      }
   325→                    },
   326→                  ),
   327→                ),
   328→              ),
   329→            ),
   330→          ],
   331→        ),
   332→      ),
   333→    );
   334→  }
   335→}
   336→
   337→// ドロップダウンの X オフセットを宣言的に解決するヘルパー
   338→Offset _resolveFollowerOffsetX({
   339→  required double baseX,
   340→  required double baseY,
   341→  required double fieldGlobalX,
   342→  required double dropdownWidth,
   343→  required double screenWidth,
   344→}) {
   345→  // 希望する左端（フィールドのグローバルXに対する相対オフセットを適用）
   346→  final desiredLeft = fieldGlobalX + baseX;
   347→  // 画面幅よりドロップダウンが広いケースを考慮して上限を下限以上に保つ
   348→  final upperBound =
   349→      screenWidth > dropdownWidth ? (screenWidth - dropdownWidth) : 0.0;
