// Flutter imports:
import 'package:flutter/material.dart';
import 'package:flutter/scheduler.dart';

// Package imports:
import 'package:flutter_hooks/flutter_hooks.dart';

// Project imports:
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/utils/build_context_ext.dart';
import 'package:baseball_detector_flutter/views/hooks/use_effect_once.dart';

class SearchableDropdownMenu<T> extends HookWidget {
  const SearchableDropdownMenu({
    required this.itemList,
    required this.hintText,
    required this.itemBuilder,
    required this.displayString,
    required this.onChanged,
    this.includeHintTextToList = false,
    this.value,
    this.decoration,
    super.key,
  });

  final List<T> itemList;
  final String hintText;
  final Widget Function(T) itemBuilder;
  final String Function(T) displayString;
  final ValueChanged<T?> onChanged;
  final bool includeHintTextToList;
  final T? value;
  final InputDecoration? decoration;

  @override
  Widget build(BuildContext context) {
    final layerLink = useMemoized(() => LayerLink());
    final overlayEntryRef = useRef<OverlayEntry?>(null);
    final controller = useTextEditingController();
    final focusNode = useFocusNode();
    final selectedRef = useRef<T?>(value);

    void hideOverlay() {
      overlayEntryRef.value?.remove();
      overlayEntryRef.value = null;
    }

    void showOverlay() {
      if (overlayEntryRef.value != null) return;

      overlayEntryRef.value = createOverlayEntry(
        context: context,
        layerLink: layerLink,
        controller: controller,
        onTap: () {
          // フィールド外タップで閉じる
          focusNode.unfocus();
          hideOverlay();
        },
        onSelect: (item) {
          onChanged(item);
          controller.text = item != null ? displayString(item) : '';
          // 選択後はフォーカスを外して閉じる
          focusNode.unfocus();
          hideOverlay();
        },
      );

      Overlay.of(context).insert(overlayEntryRef.value!);
    }

    // 入力変化でリスト更新のため Overlay を再描画
    void requestOverlayRebuild() {
      if (overlayEntryRef.value == null) return;
      final phase = WidgetsBinding.instance.schedulerPhase;
      if (phase == SchedulerPhase.idle ||
          phase == SchedulerPhase.postFrameCallbacks) {
        overlayEntryRef.value!.markNeedsBuild();
      } else {
        WidgetsBinding.instance.addPostFrameCallback((_) {
          overlayEntryRef.value?.markNeedsBuild();
        });
      }
    }

    // 初期選択値と表示テキストの同期
    useEffect(() {
      selectedRef.value = value;
      if (value != null) {
        controller.text = displayString(value as T);
      } else if (!focusNode.hasFocus && controller.text.isNotEmpty) {
        // フォーカス外かつ選択解除された場合はテキストも消す
        controller.text = '';
      }
      return null;
    }, [value]);

    // フォーカスで開閉
    useEffectOnce(() {
      // 文字列比較ユーティリティ: 前後空白を無視しつつ大文字小文字も区別しないで比較する
      bool equalsIgnoreCaseTrim(String a, String b) =>
          a.trim().toLowerCase() == b.trim().toLowerCase();

      // 入力テキストと完全一致（空白・大小無視）する候補 T を探す
      T? findExactItemByText(String text) {
        final q = text.trim();
        if (q.isEmpty) return null;
        for (final e in itemList) {
          if (equalsIgnoreCaseTrim(displayString(e), q)) return e;
        }
        return null;
      }

      // 選択値に応じてテキストフィールドを同期（選択が null なら入力をクリア）
      void syncTextToSelection(T? selection) {
        if (selection != null) {
          controller.text = displayString(selection);
        } else {
          controller.clear();
        }
      }

      // テキストフィールドが「現在選択の表示文字列」と同一なら、検索しやすいように一旦クリア
      void clearIfShowingSelectedText() {
        final current = selectedRef.value;
        if (current == null) return;
        final selectedText = displayString(current as T);
        if (equalsIgnoreCaseTrim(controller.text, selectedText)) {
          controller.clear();
        }
      }

      // フォーカス喪失時の確定処理:
      // 1) 入力と完全一致する候補があれば選択して onChanged を発火
      // 2) 一致が無ければ既存の選択へ戻す（未選択ならクリア）
      void applyExactMatchOrRestore() {
        final exact = findExactItemByText(controller.text);

        if (exact != null) {
          if (selectedRef.value != exact) {
            onChanged(exact);
            selectedRef.value = exact;
          }
          syncTextToSelection(exact);
          return;
        }

        // 一致なし: 既存選択へ戻す or クリア
        syncTextToSelection(selectedRef.value);
      }

      void focusListener() {
        if (focusNode.hasFocus) {
          // 既定値の表示文字列が入っている場合は検索開始しやすいようにクリア
          clearIfShowingSelectedText();
          showOverlay();
        } else {
          // フォーカスが外れたら、完全一致があれば確定、なければ元に戻す
          applyExactMatchOrRestore();
          hideOverlay();
        }
      }

      focusNode.addListener(focusListener);
      controller.addListener(requestOverlayRebuild);
      return () {
        focusNode.removeListener(focusListener);
        controller.removeListener(requestOverlayRebuild);
        hideOverlay();
      };
    });

    return CompositedTransformTarget(
      link: layerLink,
      child: TextField(
        controller: controller,
        focusNode: focusNode,
        readOnly: false,
        onTap: showOverlay,
        style: Theme.of(context).textTheme.bodyLarge,
        decoration: (() {
          final defaultDecoration = InputDecoration(
            border: OutlineInputBorder(
              borderRadius: BorderRadius.circular(4),
            ),
            contentPadding:
                const EdgeInsets.symmetric(vertical: 16, horizontal: 12),
          );

          final base =
              (decoration ?? defaultDecoration).copyWith(hintText: hintText);

          final resolvedSuffix = base.suffixIcon ??
              ((controller.text.isNotEmpty || value != null)
                  ? IconButton(
                      icon: const Icon(Icons.clear, size: 18),
                      onPressed: () {
                        controller.clear();
                        onChanged(null);
                        if (focusNode.hasFocus) showOverlay();
                      },
                    )
                  : const Icon(Icons.arrow_drop_down));

          return base.copyWith(
            suffixIcon: resolvedSuffix,
          );
        })(),
      ),
    );
  }

  // OverlayEntry を作るローカルメソッド
  OverlayEntry createOverlayEntry({
    required BuildContext context,
    required LayerLink layerLink,
    required TextEditingController controller,
    required VoidCallback onTap,
    required ValueChanged<T?> onSelect,
  }) {
    final renderBox = context.findRenderObject() as RenderBox;
    final size = renderBox.size;
    final offset = renderBox.localToGlobal(Offset.zero);

    List<T> filtered() {
      final q = controller.text.trim().toLowerCase();
      if (q.isEmpty) return itemList;
      return itemList.where((e) {
        final s = displayString(e).toLowerCase();
        return s.contains(q);
      }).toList();
    }

    const double baseX = 0.0;
    final double baseY = size.height;

    return OverlayEntry(
      builder: (context) => GestureDetector(
        behavior: HitTestBehavior.translucent,
        onTap: onTap,
        child: Stack(
          children: [
            Positioned(
              left: offset.dx,
              top: offset.dy,
              width: size.width,
              child: CompositedTransformFollower(
                link: layerLink,
                showWhenUnlinked: false,
                offset: _resolveFollowerOffsetX(
                  baseX: baseX,
                  baseY: baseY,
                  fieldGlobalX: offset.dx,
                  dropdownWidth: size.width,
                  screenWidth: MediaQuery.of(context).size.width,
                ),
                child: Material(
                  elevation: 8,
                  shape: RoundedRectangleBorder(
                    borderRadius: BorderRadius.circular(8.0),
                    side: BorderSide(
                      color:
                          Theme.of(context).dividerColor.withValues(alpha: 0.6),
                    ),
                  ),
                  clipBehavior: Clip.antiAlias,
                  child: Builder(
                    builder: (context) {
                      final items = filtered();
                      final maxHeightPx = context.screenHeight * 0.3;
                      const tileHeight = 56.0; // 1行の標準行高

                      final itemCount = (items.isEmpty ? 1 : items.length) +
                          (includeHintTextToList ? 1 : 0);
                      final desiredHeight = itemCount * tileHeight;
                      final overlayHeight = desiredHeight <= maxHeightPx
                          ? desiredHeight.toDouble()
                          : maxHeightPx;

                      if (items.isEmpty) {
                        return SizedBox(
                          height: overlayHeight,
                          child: ListView(
                            padding: EdgeInsets.zero,
                            children: [
                              if (includeHintTextToList)
                                ListTile(
                                  title: Text(hintText),
                                  onTap: () => onSelect(null),
                                  selected:
                                      value == null && controller.text.isEmpty,
                                ),
                              ListTile(
                                title: Text(context.l10n.common__no_data),
                              ),
                            ],
                          ),
                        );
                      } else {
                        return SizedBox(
                          height: overlayHeight,
                          child: ListTileTheme(
                            child: ListView(
                              padding: EdgeInsets.zero,
                              children: [
                                if (includeHintTextToList)
                                  ListTile(
                                    title: Text(hintText),
                                    onTap: () => onSelect(null),
                                    selected: value == null &&
                                        controller.text.isEmpty,
                                  ),
                                ...items.map(
                                  (item) => ListTile(
                                    title: itemBuilder(item),
                                    onTap: () => onSelect(item),
                                    selected: value == item,
                                  ),
                                ),
                              ],
                            ),
                          ),
                        );
                      }
                    },
                  ),
                ),
              ),
            ),
          ],
        ),
      ),
    );
  }
}

// ドロップダウンの X オフセットを宣言的に解決するヘルパー
Offset _resolveFollowerOffsetX({
  required double baseX,
  required double baseY,
  required double fieldGlobalX,
  required double dropdownWidth,
  required double screenWidth,
}) {
  // 希望する左端（フィールドのグローバルXに対する相対オフセットを適用）
  final desiredLeft = fieldGlobalX + baseX;
  // 画面幅よりドロップダウンが広いケースを考慮して上限を下限以上に保つ
  final upperBound =
      screenWidth > dropdownWidth ? (screenWidth - dropdownWidth) : 0.0;
  // 0..upperBound にクランプし、フォロワー基準の相対Xへ差し戻す
  final clampedLeft = desiredLeft.clamp(0.0, upperBound);
  return Offset(clampedLeft - fieldGlobalX, baseY);
}

