/// A page widget class to manage player lists.
class PlayersPage extends HookConsumerWidget {
  const PlayersPage({super.key});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final teamId = ref.watch(profileStorageProvider).getTeamId()!;
    final accessibleContents =
        ref.watch(userAccessibleContentsControllerProvider);
    final canAddPlayer = accessibleContents?.hasPrivilegesFor(
          teamId,
          RoleDomain.basic,
          RoleLevel.write,
          false,
        ) ??
        false;

    // Filter state
    final selectedPlayer = useState<Player?>(null);
    final allPlayersAsync = ref.watch(allPlayersProvider);

    return Scaffold(
      body: SafeArea(
        child: Padding(
          padding: HomePage.bodyPadding,
          child: Column(
            children: [
              // Filter section
              Padding(
                padding: const EdgeInsets.only(bottom: 12),
                child: allPlayersAsync.when(
                  data: (players) => SizedBox(
                    height: 48,
                    child: SearchableDropdownMenu<Player>(
                      value: selectedPlayer.value,
                      onChanged: (player) {
                        selectedPlayer.value = player;
                      },
                      itemList: players,
                      itemBuilder: (p) => Text(p.name ?? ''),
                      displayString: (p) => p.name ?? '',
                      hintText: context.l10n.sessions_page__filter_hint,
                      includeHintTextToList: true,
                      decoration: InputDecoration(
                        contentPadding: const EdgeInsets.symmetric(
                          vertical: 8,
                          horizontal: 12,
                        ),
                        border: OutlineInputBorder(
                          borderRadius: BorderRadius.circular(8),
                        ),
                      ),
                    ),
                  ),
                  loading: () => const SizedBox.shrink(),
                  error: (_, __) => const SizedBox.shrink(),
                ),
              ),
              // Player list
              Expanded(
                child: PagingHelper<PlayerListController, Player>(
                  provider: playerListControllerProvider,
                  contentBuilder: (PagingData<Player> data, Widget? endItemView) {
                    // Apply filter if a player is selected
                    final filteredItems = selectedPlayer.value != null
                        ? data.items
                            .where((p) => p.id == selectedPlayer.value!.id)
                            .toList()
                        : data.items;

                    if (filteredItems.isEmpty) {
                      return EmptyView(
                        icon: Icons.people_outline,
                        message: selectedPlayer.value != null
                            ? context.l10n.common__no_data
                            : context.l10n.players_page__have_no_data,
                        height: context.screenHeight * 0.8,
                      );
                    }
                    return ListView(
                      children: [
                        ...filteredItems.map((player) => PlayerCard(player: player)),
                        if (endItemView != null) endItemView else const Gap(80),
                      ],
                    );
                  },
                ),
              ),
            ],
          ),
        ),
      ),
      floatingActionButton: FloatingActionButton(
        backgroundColor: canAddPlayer
            ? null
            : context.isDarkMode
                ? ColorManager.darkSecondaryText
                : ColorManager.secondaryText,
        onPressed: canAddPlayer
            ? () {
                Navigator.of(context).pushNamed(HomeRouter.createPlayerPage);
              }
            : null,
        child: Icon(Icons.person_add_alt),
      ),
    );
  }
}

