// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:flutter_hooks/flutter_hooks.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';
import 'package:image_picker/image_picker.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/player_list_controller.dart';
import 'package:baseball_detector_flutter/data/models/dto/player/handedness.dart';
import 'package:baseball_detector_flutter/data/models/failure/failure.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/views/components/birthday_form_field.dart';
import 'package:baseball_detector_flutter/views/components/custom_app_bar.dart';
import 'package:baseball_detector_flutter/views/components/custom_text_form_field.dart';
import 'package:baseball_detector_flutter/views/components/edit_page_layout.dart';
import 'package:baseball_detector_flutter/views/components/editable_avatar.dart';
import 'package:baseball_detector_flutter/views/constants/input_max_lengths.dart';
import 'package:baseball_detector_flutter/views/hooks/use_operation.dart';
import 'package:baseball_detector_flutter/views/hooks/use_single_action.dart';
import 'package:baseball_detector_flutter/views/pages/home/players/hooks/use_handedness.dart';
import 'package:baseball_detector_flutter/views/validators/player.dart';

class CreatePlayerPage extends HookConsumerWidget {
  const CreatePlayerPage({super.key});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final nameController = useTextEditingController();
    final noteController = useTextEditingController();
    final nameError = useState<PlayerNameError?>(null);
    final selectedImage = useState<XFile?>(null);
    final pitching = usePitchingHand(Handedness.none);
    final hitting = useHittingHand(Handedness.none);
    final birthday = useState<DateTime?>(null);
    final handleOperation = useOperation();

    final runCreate = useSingleAction<void>(asyncCallback: (_) async {
      nameError.value = validatePlayerName(nameController.text);

      final isValid = nameError.value == null;
      if (!isValid) return;

      await handleOperation(
        operation: ref.read(playerListControllerProvider.notifier).createPlayer(
              playerName: nameController.text,
              note: noteController.text,
              pitchingHand: pitching.currentHand.value,
              hittingHand: hitting.currentHand.value,
              imageFilePath: selectedImage.value?.path,
              birthday: birthday.value,
            ),
        onSucceeded: (data) {
          Navigator.of(context).pop();
          return context.l10n.create_player_page__create_player_succeeded;
        },
        onFailed: (error) {
          Navigator.of(context).pop();
          return '${context.l10n.create_player_page__create_player_failed}: ${error.translate(context.l10n)}';
        },
        shouldSendErrorLog: (failure) => failure is! UnprocessableEntityFailure,
      );
    });

    return Scaffold(
      appBar: CustomAppBar(
        isBackNavigation: true,
        title: context.l10n.create_player_page__create_new_player,
      ),
      body: EditPageLayout(
        onPressed: runCreate,
        children: [
          Center(
            child: EditableAvatar(
              selectedImage: selectedImage,
              size: 104,
            ),
          ),
          const SizedBox(height: 24),
          CustomTextFormField(
            controller: nameController,
            label: Text(
              context.l10n.create_player_page__name_label,
            ),
            maxLength: InputMaxLengths.playerName,
            errorText: translatePlayerNameError(context, nameError.value),
          ),
          const SizedBox(height: 24),
          CustomTextFormField(
            controller: noteController,
            label: Text(
              context.l10n.create_player_page__note_label,
            ),
            maxLength: InputMaxLengths.playerMemo,
          ),
          const SizedBox(height: 24),
          pitching.pitchingHandSelector,
          const SizedBox(height: 24),
          hitting.hittingHandSelector,

/// {@category Widgets}
library;

// Dart imports:
import 'dart:io';
import 'dart:ui';

// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:flutter_hooks/flutter_hooks.dart';
import 'package:image_picker/image_picker.dart';

// Project imports:
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/utils/snack_bar.dart';
import 'package:baseball_detector_flutter/views/components/s3_image.dart';
import 'package:baseball_detector_flutter/views/themes/color_manager.dart';

class EditableAvatar extends HookWidget {
  const EditableAvatar({
    super.key,
    this.s3ImageUrl,
    this.selectedImage,
    this.defaultImage,
    this.onTap,
    this.size = 132,
    this.borderRadius = 4,
  });

  final String? s3ImageUrl;
  final ValueNotifier<XFile?>? selectedImage;
  final Widget? defaultImage;
  final VoidCallback? onTap;
  final double size;
  final double borderRadius;

  @override
  Widget build(BuildContext context) {
    return GestureDetector(
      onTap: onTap ??
          () async {
            try {
              final picker = ImagePicker();
              final file = await picker.pickImage(
                source: ImageSource.gallery,
                requestFullMetadata: false,
              );
              if (file == null) {
                return;
              }
              selectedImage?.value = file;
            } catch (e) {
              if (!context.mounted) return;
              debugPrint('Error picking image: $e');
              context.showErrorSnackBar(
                context.l10n.editable_avatar_error,
              );
            }
          },
      child: SizedBox(
        width: size,
        height: size,
        child: ClipRRect(
          borderRadius: BorderRadius.circular(borderRadius),
          child: ColoredBox(
            color: ColorManager.avatarFill,
            child: Stack(children: [
              SizedBox.expand(
                child: selectedImage?.value != null
                    ? Image.file(
                        File(selectedImage!.value!.path),
                      )
                    : s3ImageUrl != null
                        ? S3Image(
                            url: s3ImageUrl!,
                            imageErrorBuilder: (_, __, ___) =>
                                defaultImage ??
                                Icon(
                                  Icons.upload_file_outlined,
                                  color: ColorManager.iconForeground,
                                ),
                          )
                        : defaultImage ??
                            Icon(
                              Icons.upload_file_outlined,
                              color: ColorManager.iconForeground,
                            ),
              ),
              Positioned(
                bottom: 0,
                child: ClipRect(
                  child: BackdropFilter(
                    filter: ImageFilter.blur(
                      sigmaX: 1.5,
                      sigmaY: 1.5,
                    ),
                    child: Container(
                      height: 30,
                      width: size,
                      decoration: const BoxDecoration(
                        color: ColorManager.teamImageEditBackground,
                      ),
                      child: Center(
                        child: Text(
                          context.l10n.edit_team_page__edit,
                          style: const TextStyle(
                            color: ColorManager.light,
                          ),
                          textAlign: TextAlign.center,
                        ),
                      ),
                    ),
                  ),
                ),
              ),
            ]),
          ),
        ),
      ),
    );
  }
}

