// Flutter imports:

// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:cached_network_image/cached_network_image.dart';

class S3Image extends StatelessWidget {
  const S3Image({
    required this.url,
    this.placeholder,
    this.imageErrorBuilder,
    super.key,
  });

  final String? url;
  final Widget? placeholder;
  final Widget Function(BuildContext, String, Object)? imageErrorBuilder;

  @override
  Widget build(BuildContext context) {
    assert(
      url != null || placeholder != null,
      'url or placeholder must be provided',
    );

    if (url == null) return placeholder!;

    return CachedNetworkImage(
      imageUrl: url!,
      cacheKey: _dropSignedParams,
      fit: BoxFit.cover,
      fadeOutDuration: const Duration(milliseconds: 1),
      fadeInDuration: const Duration(milliseconds: 300),
      errorWidget: imageErrorBuilder,
    );
  }

  String? get _dropSignedParams {
    if (url == null) return null;

    final uri = Uri.tryParse(url!);
    if (uri == null) return url;

    final params = Map.fromEntries(uri.queryParametersAll.entries);
    params.remove('X-Amz-Algorithm');
    params.remove('X-Amz-Content-Sha256');
    params.remove('X-Amz-Credential');
    params.remove('X-Amz-Date');
    params.remove('X-Amz-Expires');
    params.remove('X-Amz-Signature');
    params.remove('X-Amz-SignedHeaders');

    return Uri(
      scheme: uri.scheme,
      host: uri.host,
      port: uri.port,
      path: uri.path,
      queryParameters: params.isNotEmpty ? params : null,
    ).toString();
  }
}

