    20→import 'package:baseball_detector_flutter/providers/repository_provider.dart';
    21→
    22→part 'session_list_controller.g.dart';
    23→
    24→/// A controller class that manages [Session] list.
    25→///
    26→/// This controller refreshes itself when
    27→/// - [repositoryProvider] updated.
    28→/// - [loginStateControllerProvider] updated.
    29→/// - [sessionFilterParametersNotifierProvider] updated.
    30→/// - [PlayerListController] runs [PlayerListController.updatePlayer].
    31→///
    32→/// Note: This controller just handles abstract repository.
    33→/// This means that the controller does not care
    34→/// the implementation of its repository is either remote DB or local cache.
    35→/// Therefore do not use anything related to a specific implementation of repository
    36→/// (e.g., the login state of the remote DB).
    37→@Riverpod(keepAlive: true)
    38→class SessionListController extends _$SessionListController
    39→    with PagePagingNotifierMixin<Session> {
    40→  static const int pageSize = 50;
    41→
    42→  @override
    43→  Future<PagingData<Session>> build() {
    44→    ref.watch(loginStateControllerProvider);
    45→    ref.watch(repositoryProvider);
    46→    ref.watch(userAccessibleContentsControllerProvider);
    47→    final filterParams = ref.watch(sessionFilterParametersNotifierProvider);
    48→    return fetch(
    49→      page: AutoDisposePagePagingNotifierMixin.initialPage,
    50→      pageSize: pageSize,
    51→      filterParams: filterParams,
    52→    );
    53→  }
    54→
    55→  @override
    56→  Future<PagingData<Session>> fetch({
    57→    required int page,
    58→    required int pageSize,
    59→    SessionFilterParameters? filterParams,
    60→  }) async {
    61→    filterParams ??= ref.read(sessionFilterParametersNotifierProvider);
    62→
    63→    final res = await ref.read(repositoryProvider).getSessions(
    64→          page: page,
    65→          pageSize: pageSize,
    66→          playerId: filterParams?.player?.id,
    67→          location: filterParams?.location,
    68→          startDate: filterParams?.startDate,
    69→          endDate: filterParams?.endDate,
    70→        );
    71→
    72→    checkResultForMaintenance(ref, res);
    73→    if (!res.hasRight) {
    74→      throw res.left;
    75→    }
    76→    return PagingData<Session>(
    77→      items: res.right.sessions,
    78→      page: page,
    79→      pageSize: pageSize,
    80→      total: res.right.total,
    81→      hasMore: res.right.sessions.length + page * pageSize < res.right.total,
    82→    );
    83→  }
    84→
    85→  Future<Result<Failure, void>> deleteSession(String sessionId) async {
    86→    final res =
    87→        await ref.read(repositoryProvider).deleteSession(sessionId: sessionId);
    88→    checkResultForMaintenance(ref, res);
    89→    if (res.hasRight && state.value != null) {
    90→      final current = state.value!;
    91→      final newItems = current.items.where((s) => s.id != sessionId).toList();
    92→      state = AsyncData(current.copyWith(items: newItems));
    93→    }
    94→    return res;
    95→  }
    96→
    97→  /// Update a [Session] model in the repository.
    98→  Future<Result<Failure, Session>> editSession({
    99→    required String sessionId,
   100→    required String playerId,
   101→    required String note,
   102→    required String location,
   103→    required String title,
   104→  }) async {
   105→    final res = await ref.read(repositoryProvider).editSession(
   106→          playerId: playerId,
   107→          sessionId: sessionId,
   108→          location: location,
